# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
import json
import uuid
from datetime import datetime
from typing import Dict, Set, Optional
from dataclasses import dataclass, asdict
from enum import Enum

class ItemRarity(Enum):
    COMMON = "common"
    UNCOMMON = "uncommon"
    RARE = "rare"
    EPIC = "epic"
    LEGENDARY = "legendary"

@dataclass
class Item:
    item_id: str
    name: str
    rarity: str
    quantity: int
    owner_id: Optional[str] = None
    
    def to_dict(self):
        return {
            'item_id': self.item_id,
            'name': self.name,
            'rarity': self.rarity,
            'quantity': self.quantity,
            'owner_id': self.owner_id
        }

class Player:
    def __init__(self, player_id: str, username: str):
        self.player_id = player_id
        self.username = username
        self.inventory: Dict[str, Item] = {}
        self.gold = 1000
        self.trade_lock = asyncio.Lock()
        
    def add_item(self, item: Item):
        if item.item_id in self.inventory:
            self.inventory[item.item_id].quantity += item.quantity
        else:
            item.owner_id = self.player_id
            self.inventory[item.item_id] = item
            
    def remove_item(self, item_id: str, quantity: int) -> bool:
        if item_id not in self.inventory:
            return False
        if self.inventory[item_id].quantity < quantity:
            return False
        self.inventory[item_id].quantity -= quantity
        if self.inventory[item_id].quantity == 0:
            del self.inventory[item_id]
        return True
    
    def get_inventory(self):
        return {item_id: item.to_dict() for item_id, item in self.inventory.items()}

class TradeRequest:
    def __init__(self, trade_id: str, initiator_id: str, target_id: str):
        self.trade_id = trade_id
        self.initiator_id = initiator_id
        self.target_id = target_id
        self.initiator_items: Dict[str, int] = {}
        self.target_items: Dict[str, int] = {}
        self.initiator_gold = 0
        self.target_gold = 0
        self.initiator_ready = False
        self.target_ready = False
        self.status = "pending"
        self.created_at = datetime.now()

class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.connections: Dict[str, websockets.WebSocketServerProtocol] = {}
        self.trades: Dict[str, TradeRequest] = {}
        self.trade_lock = asyncio.Lock()
        
    async def register_player(self, websocket, player_id: str, username: str):
        if player_id not in self.players:
            player = Player(player_id, username)
            self.players[player_id] = player
            self._initialize_starter_inventory(player)
        else:
            player = self.players[player_id]
        
        self.connections[player_id] = websocket
        return player
    
    def _initialize_starter_inventory(self, player: Player):
        starter_items = [
            Item(str(uuid.uuid4()), "Health Potion", ItemRarity.COMMON.value, 5),
            Item(str(uuid.uuid4()), "Mana Potion", ItemRarity.COMMON.value, 5),
            Item(str(uuid.uuid4()), "Iron Sword", ItemRarity.UNCOMMON.value, 1),
        ]
        for item in starter_items:
            player.add_item(item)
    
    async def handle_client(self, websocket, path):
        player_id = None
        try:
            async for message in websocket:
                data = json.loads(message)
                action = data.get('action')
                
                if action == 'connect':
                    player_id = data.get('player_id', str(uuid.uuid4()))
                    username = data.get('username', f'Player_{player_id[:8]}')
                    player = await self.register_player(websocket, player_id, username)
                    await self.send_message(websocket, {
                        'type': 'connected',
                        'player_id': player_id,
                        'username': username,
                        'inventory': player.get_inventory(),
                        'gold': player.gold
                    })
                
                elif action == 'get_inventory':
                    if player_id and player_id in self.players:
                        player = self.players[player_id]
                        await self.send_message(websocket, {
                            'type': 'inventory',
                            'inventory': player.get_inventory(),
                            'gold': player.gold
                        })
                
                elif action == 'initiate_trade':
                    await self.initiate_trade(player_id, data.get('target_id'))
                
                elif action == 'add_trade_item':
                    await self.add_trade_item(
                        player_id,
                        data.get('trade_id'),
                        data.get('item_id'),
                        data.get('quantity', 1)
                    )
                
                elif action == 'remove_trade_item':
                    await self.remove_trade_item(
                        player_id,
                        data.get('trade_id'),
                        data.get('item_id')
                    )
                
                elif action == 'add_trade_gold':
                    await self.add_trade_gold(
                        player_id,
                        data.get('trade_id'),
                        data.get('amount', 0)
                    )
                
                elif action == 'ready_trade':
                    await self.ready_trade(player_id, data.get('trade_id'))
                
                elif action == 'cancel_trade':
                    await self.cancel_trade(player_id, data.get('trade_id'))
                
                elif action == 'transfer_item':
                    await self.transfer_item(
                        player_id,
                        data.get('target_id'),
                        data.get('item_id'),
                        data.get('quantity', 1)
                    )
                
        except websockets.exceptions.ConnectionClosed:
            pass
        finally:
            if player_id and player_id in self.connections:
                del self.connections[player_id]
    
    async def send_message(self, websocket, message):
        try:
            await websocket.send(json.dumps(message))
        except:
            pass
    
    async def notify_player(self, player_id: str, message: dict):
        if player_id in self.connections:
            await self.send_message(self.connections[player_id], message)
    
    async def initiate_trade(self, initiator_id: str, target_id: str):
        if initiator_id not in self.players or target_id not in self.players:
            await self.notify_player(initiator_id, {
                'type': 'error',
                'message': 'Player not found'
            })
            return
        
        trade_id = str(uuid.uuid4())
        trade = TradeRequest(trade_id, initiator_id, target_id)
        
        async with self.trade_lock:
            self.trades[trade_id] = trade
        
        await self.notify_player(initiator_id, {
            'type': 'trade_initiated',
            'trade_id': trade_id,
            'target': self.players[target_id].username
        })
        
        await self.notify_player(target_id, {
            'type': 'trade_request',
            'trade_id': trade_id,
            'initiator': self.players[initiator_id].username,
            'initiator_id': initiator_id
        })
    
    async def add_trade_item(self, player_id: str, trade_id: str, item_id: str, quantity: int):
        if trade_id not in self.trades:
            await self.notify_player(player_id, {
                'type': 'error',
                'message': 'Trade not found'
            })
            return
        
        trade = self.trades[trade_id]
        player = self.players[player_id]
        
        if item_id not in player.inventory:
            await self.notify_player(player_id, {
                'type': 'error',
                'message': 'Item not in inventory'
            })
            return
        
        if player.inventory[item_id].quantity < quantity:
            await self.notify_player(player_id, {
                'type': 'error',
                'message': 'Insufficient item quantity'
            })
            return
        
        if player_id == trade.initiator_id:
            trade.initiator_items[item_id] = quantity
            trade.initiator_ready = False
        elif player_id == trade.target_id:
            trade.target_items[item_id] = quantity
            trade.target_ready = False
        
        await self._broadcast_trade_update(trade)
    
    async def remove_trade_item(self, player_id: str, trade_id: str, item_id: str):
        if trade_id not in self.trades:
            return
        
        trade = self.trades[trade_id]
        
        if player_id == trade.initiator_id:
            if item_id in trade.initiator_items:
                del trade.initiator_items[item_id]
            trade.initiator_ready = False
        elif player_id == trade.target_id:
            if item_id in trade.target_items:
                del trade.target_items[item_id]
            trade.target_ready = False
        
        await self._broadcast_trade_update(trade)
    
    async def add_trade_gold(self, player_id: str, trade_id: str, amount: int):
        if trade_id not in self.trades:
            return
        
        trade = self.trades[trade_id]
        player = self.players[player_id]
        
        if amount < 0 or amount > player.gold:
            await self.notify_player(player_id, {
                'type': 'error',
                'message': 'Invalid gold amount'
            })
            return
        
        if player_id == trade.initiator_id:
            trade.initiator_gold = amount
            trade.initiator_ready = False
        elif player_id == trade.target_id:
            trade.target_gold = amount
            trade.target_ready = False
        
        await self._broadcast_trade_update(trade)
    
    async def ready_trade(self, player_id: str, trade_id: str):
        if trade_id not in self.trades:
            return
        
        trade = self.trades[trade_id]
        
        if player_id == trade.initiator_id:
            trade.initiator_ready = True
        elif player_id == trade.target_id:
            trade.target_ready = True
        
        await self._broadcast_trade_update(trade)
        
        if trade.initiator_ready and trade.target_ready:
            await self.execute_trade(trade_id)
    
    async def execute_trade(self, trade_id: str):
        if trade_id not in self.trades:
            return
        
        trade = self.trades[trade_id]
        initiator = self.players[trade.initiator_id]
        target = self.players[trade.target_id]
        
        async with initiator.trade_lock:
            async with target.trade_lock:
                if not self._validate_trade(trade, initiator, target):
                    await self.notify_player(trade.initiator_id, {
                        'type': 'error',
                        'message': 'Trade validation failed'
                    })
                    await self.notify_player(trade.target_id, {
                        'type': 'error',
                        'message': 'Trade validation failed'
                    })
                    await self.cancel_trade(trade.initiator_id, trade_id)
                    return
                
                for item_id, quantity in trade.initiator_items.items():
                    item = initiator.inventory[item_id]
                    initiator.remove_item(item_id, quantity)
                    new_item = Item(item.item_id, item.name, item.rarity, quantity)
                    target.add_item(new_item)
                
                for item_id, quantity in trade.target_items.items():
                    item = target.inventory[item_id]
                    target.remove_item(item_id, quantity)
                    new_item = Item(item.item_id, item.name, item.rarity, quantity)
                    initiator.add_item(new_item)
                
                initiator.gold -= trade.initiator_gold
                initiator.gold += trade.target_gold
                target.gold -= trade.target_gold
                target.gold += trade.initiator_gold
                
                await self.notify_player(trade.initiator_id, {
                    'type': 'trade_completed',
                    'trade_id': trade_id,
                    'inventory': initiator.get_inventory(),
                    'gold': initiator.gold
                })
                
                await self.notify_player(trade.target_id, {
                    'type': 'trade_completed',
                    'trade_id': trade_id,
                    'inventory': target.get_inventory(),
                    'gold': target.gold
                })
                
                async with self.trade_lock:
                    del self.trades[trade_id]
    
    def _validate_trade(self, trade: TradeRequest, initiator: Player, target: Player) -> bool:
        for item_id, quantity in trade.initiator_items.items():
            if item_id not in initiator.inventory:
                return False
            if initiator.inventory[item_id].quantity < quantity:
                return False
        
        for item_id, quantity in trade.target_items.items():
            if item_id not in target.inventory:
                return False
            if target.inventory[item_id].quantity < quantity:
                return False
        
        if initiator.gold < trade.initiator_gold:
            return False
        if target.gold < trade.target_gold:
            return False
        
        return True
    
    async def cancel_trade(self, player_id: str, trade_id: str):
        if trade_id not in self.trades:
            return
        
        trade = self.trades[trade_id]
        
        await self.notify_player(trade.initiator_id, {
            'type': 'trade_cancelled',
            'trade_id': trade_id
        })
        
        await self.notify_player(trade.target_id, {
            'type': 'trade_cancelled',
            'trade_id': trade_id
        })
        
        async with self.trade_lock:
            del self.trades[trade_id]
    
    async def _broadcast_trade_update(self, trade: TradeRequest):
        trade_data = {
            'type': 'trade_update',
            'trade_id': trade.trade_id,
            'initiator_items': {
                item_id: {
                    'quantity': qty,
                    'name': self.players[trade.initiator_id].inventory[item_id].name
                }
                for item_id, qty in trade.initiator_items.items()
            },
            'target_items': {
                item_id: {
                    'quantity': qty,
                    'name': self.players[trade.target_id].inventory[item_id].name
                }
                for item_id, qty in trade.target_items.items()
            },
            'initiator_gold': trade.initiator_gold,
            'target_gold': trade.target_gold,
            'initiator_ready': trade.initiator_ready,
            'target_ready': trade.target_ready
        }
        
        await self.notify_player(trade.initiator_id, trade_data)
        await self.notify_player(trade.target_id, trade_data)
    
    async def transfer_item(self, sender_id: str, receiver_id: str, item_id: str, quantity: int):
        if sender_id not in self.players or receiver_id not in self.players:
            await self.notify_player(sender_id, {
                'type': 'error',
                'message': 'Player not found'
            })
            return
        
        sender = self.players[sender_id]
        receiver = self.players[receiver_id]
        
        async with sender.trade_lock:
            async with receiver.trade_lock:
                if item_id not in sender.inventory:
                    await self.notify_player(sender_id, {
                        'type': 'error',
                        'message': 'Item not in inventory'
                    })
                    return
                
                if sender.inventory[item_id].quantity < quantity:
                    await self.notify_player(sender_id, {
                        'type': 'error',
                        'message': 'Insufficient item quantity'
                    })
                    return
                
                item = sender.inventory[item_id]
                sender.remove_item(item_id, quantity)
                new_item = Item(item.item_id, item.name, item.rarity, quantity)
                receiver.add_item(new_item)
                
                await self.notify_player(sender_id, {
                    'type': 'item_transferred',
                    'item_id': item_id,
                    'quantity': quantity,
                    'receiver': receiver.username,
                    'inventory': sender.get_inventory()
                })
                
                await self.notify_player(receiver_id, {
                    'type': 'item_received',
                    'item_id': item_id,
                    'quantity': quantity,
                    'sender': sender.username,
                    'inventory': receiver.get_inventory()
                })

async def main():
    server = GameServer()
    async with websockets.serve(server.handle_client, "localhost", 8765):
        print("MMO Game Server running on ws://localhost:8765")
        await asyncio.Future()

if __name__ == "__main__":
    asyncio.run(main())